const item = $input.first();
const binary = { ...(item.binary || {}) };
const binaryKeys = Object.keys(binary);

const audioKey =
  binaryKeys.find((key) => key === 'audio') ??
  binaryKeys.find((key) => key.startsWith('audio')) ??
  binaryKeys[0];

if (!audioKey) {
  throw new Error(
    'No audio file received from ZapTask. Check ZapTask sent multipart field "audio". Binary keys: ' +
      (binaryKeys.join(', ') || 'none'),
  );
}

const raw = item.json?.body ?? item.json ?? {};
const meta = raw.body ?? raw;

return [
  {
    json: {
      user_id: meta.user_id,
      user_name: meta.user_name,
      user_email: meta.user_email,
      company_id: meta.company_id,
      duration_seconds: meta.duration_seconds,
      stopped_reason: meta.stopped_reason,
      recorded_at: meta.recorded_at,
      debug_binary_key_used: audioKey,
    },
    binary: audioKey === 'audio' ? binary : { audio: binary[audioKey] },
  },
];

const meta = $('Normalize Webhook Input').first().json;
const transcribe = $input.first().json;

const transcript = (transcribe.text ?? '').trim();

if (!transcript) {
  throw new Error('No speech was detected in the recording.');
}

return [
  {
    json: {
      transcript,
      user_id: meta.user_id,
      user_name: meta.user_name,
      user_email: meta.user_email,
      company_id: meta.company_id,
      duration_seconds: meta.duration_seconds,
      stopped_reason: meta.stopped_reason,
      recorded_at: meta.recorded_at,
    },
  },
];

